import { useState, useEffect, useRef } from "react";
import "@/App.css";
import { motion, useInView } from "framer-motion";
import { 
  ArrowRight, 
  Phone, 
  Check, 
  X, 
  Radar, 
  Camera, 
  Cpu, 
  Trophy,
  Star,
  Nfc,
  ShieldCheck,
  MapPin,
  TrendingUp,
  ChevronDown
} from "lucide-react";
import { Button } from "@/components/ui/button";
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/components/ui/accordion";

// Animation variants
const fadeInUp = {
  initial: { opacity: 0, y: 30 },
  animate: { opacity: 1, y: 0 },
  transition: { duration: 0.6, ease: [0.22, 1, 0.36, 1] }
};

const staggerContainer = {
  animate: {
    transition: {
      staggerChildren: 0.1
    }
  }
};

// Branded Section Header Component
const SectionHeader = ({ number, label, title, highlight, description, centered = true }) => (
  <motion.div 
    initial={{ opacity: 0, y: 30 }}
    whileInView={{ opacity: 1, y: 0 }}
    viewport={{ once: true }}
    transition={{ duration: 0.6 }}
    className={centered ? "text-center mb-8 md:mb-16" : "mb-8 md:mb-16"}
  >
    <div className={`kapta-section-marker ${centered ? "justify-center" : ""}`}>
      <span className="font-mono text-[10px] sm:text-xs text-[#1c3ff9] tracking-widest">{number}</span>
      <span className="font-mono text-[10px] sm:text-xs text-[#A1A1AA] uppercase tracking-widest">{label}</span>
    </div>
    <h2 className="text-2xl sm:text-3xl md:text-4xl lg:text-5xl font-bold text-[#0A0A0A] mb-2 md:mb-4 leading-tight">
      {title} <span className="text-[#1c3ff9]">{highlight}</span>
    </h2>
    {description && (
      <p className="text-sm md:text-base lg:text-lg text-[#52525B] max-w-2xl mx-auto px-4 md:px-0">
        {description}
      </p>
    )}
  </motion.div>
);

// Navbar Component
const Navbar = () => {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 50);
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  return (
    <motion.nav
      initial={{ y: -100 }}
      animate={{ y: 0 }}
      transition={{ duration: 0.6 }}
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
        scrolled ? "glassmorphism shadow-premium" : "bg-transparent"
      }`}
      data-testid="navbar"
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-16 md:h-20">
          <a href="#" className="flex items-center gap-2" data-testid="logo">
            <img 
              src="/logo2.webp" 
              alt="KAPTA" 
              className="h-5 sm:h-6 md:h-8 w-auto"
            />
            <div className="flex items-baseline gap-0.5">
              <span className="text-lg sm:text-xl md:text-2xl font-black tracking-tight text-[#0A0A0A]" style={{ fontFamily: 'Space Grotesk, sans-serif', fontWeight: '900', letterSpacing: '-0.02em', fontSize: 'clamp(1.1em, 2.5vw, 1.3em)' }}>KAPTA</span>
              <span className="text-sm sm:text-base md:text-lg font-medium italic text-[#1c3ff9]" style={{ 
                fontFamily: 'Inter, sans-serif', 
                textShadow: '0 0 3px rgba(28, 63, 249, 0.4), 0 0 6px rgba(28, 63, 249, 0.2)',
                filter: 'brightness(1.1)'
              }}>media</span>
            </div>
          </a>

          <div className="hidden md:flex items-center gap-8">
            <a href="#mechanism" className="text-sm font-medium text-[#52525B] hover:text-[#0A0A0A] transition-colors">
              Mécanisme
            </a>
            <a href="#pricing" className="text-sm font-medium text-[#52525B] hover:text-[#0A0A0A] transition-colors">
              Tarifs
            </a>
            <a href="#faq" className="text-sm font-medium text-[#52525B] hover:text-[#0A0A0A] transition-colors">
              FAQ
            </a>
            <Button 
              data-testid="cta-audit-desktop"
              className="bg-[#1c3ff9] hover:bg-[#1534d4] text-white rounded-full px-6 btn-shimmer"
              onClick={() => document.getElementById('contact')?.scrollIntoView({ behavior: 'smooth' })}
            >
              AUDIT GRATUIT
            </Button>
          </div>

          <a
            href="tel:0686018054"
            className="md:hidden flex items-center justify-center w-12 h-12 rounded-full bg-[#1c3ff9] text-white shadow-glow-sm"
            data-testid="cta-phone-mobile"
          >
            <Phone className="w-5 h-5" />
          </a>
        </div>
      </div>
    </motion.nav>
  );
};

// Hero Section - Clean & Visual with Google Maps Mockup
const Hero = () => {
  return (
    <section 
      className="relative min-h-screen pt-24 md:pt-28 pb-16 md:pb-20 overflow-hidden bg-white"
      data-testid="hero-section"
    >
      {/* Strong Grid Background */}
      <div className="absolute inset-0 bg-[linear-gradient(rgba(28,63,249,0.08)_1px,transparent_1px),linear-gradient(90deg,rgba(28,63,249,0.08)_1px,transparent_1px)] bg-[size:40px_40px]" />

      {/* Gradient overlay for depth */}
      <div className="absolute inset-0 bg-gradient-to-b from-white via-transparent to-white pointer-events-none" />

      {/* Soft Blue Glow */}
      <div className="absolute top-1/3 right-1/4 w-[500px] h-[500px] bg-[#1c3ff9]/10 rounded-full blur-[120px] pointer-events-none" />

      <div className="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="text-center">
          {/* Left - Text Content */}
          <div className="order-1 lg:order-1">
            {/* Badge */}
            <motion.div 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5 }}
              className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-[#1c3ff9]/5 border border-[#1c3ff9]/10 mb-6"
            >
              <span className="w-2 h-2 rounded-full bg-[#10B981] animate-pulse" />
              <span className="text-xs md:text-sm font-medium text-[#1c3ff9]">Top Google Maps en 14 jours</span>
            </motion.div>

            {/* Main Headline */}
            <motion.h1 
              initial={{ opacity: 0, y: 30 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6, delay: 0.1 }}
              className="text-4xl sm:text-5xl md:text-6xl font-bold text-[#0A0A0A] leading-[1.05] mb-6"
            >
              Votre concurrent est{" "}
              <span className="text-[#1c3ff9]">N°1</span>.
              <br />
              <span className="text-[#71717A]">Ça vous va ?</span>
            </motion.h1>

            {/* Subtitle */}
            <motion.p 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: 0.2 }}
              className="text-base md:text-lg text-[#52525B] max-w-xl mb-6 leading-relaxed"
            >
              On vous met dans le <span className="font-semibold text-[#0A0A0A]">Top Google Maps</span> avec 
              une vidéo pro + une fiche Google qui donne envie d'appeler.
            </motion.p>

            {/* Price tag */}
            <motion.p 
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ duration: 0.5, delay: 0.25 }}
              className="text-sm text-[#10B981] font-mono mb-6"
            >
              350€ · Résultats sous 30 jours ou remboursé
            </motion.p>

            {/* CTA */}
            <motion.div 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: 0.3 }}
              className="flex flex-col sm:flex-row items-center lg:items-start gap-4 mb-8"
            >
              <Button 
                data-testid="cta-hero-primary"
                size="lg"
                className="w-full sm:w-auto bg-[#1c3ff9] hover:bg-[#1534d4] text-white rounded-full px-8 py-6 text-base font-semibold shadow-glow btn-shimmer group"
                onClick={() => document.getElementById('contact')?.scrollIntoView({ behavior: 'smooth' })}
              >
                RÉSERVER MON AUDIT GRATUIT
                <ArrowRight className="ml-2 w-5 h-5 group-hover:translate-x-1 transition-transform" />
              </Button>
            </motion.div>

            {/* Stats Row */}
            <motion.div 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: 0.4 }}
              className="flex items-center justify-center lg:justify-start gap-8"
            >
              {[
                { value: "14j", label: "Résultats" },
                { value: "350€", label: "Tarif pilote" },
                { value: "5", label: "Places" },
              ].map((stat, i) => (
                <div key={i} className="text-center">
                  <p className="text-2xl md:text-3xl font-bold text-[#0A0A0A]">{stat.value}</p>
                  <p className="text-xs text-[#71717A]">{stat.label}</p>
                </div>
              ))}
            </motion.div>
          </div>
        </div>
      </div>

      {/* Scroll Indicator */}
      <motion.div 
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 1.2 }}
        className="absolute bottom-6 left-1/2 -translate-x-1/2"
      >
        <motion.div
          animate={{ y: [0, 8, 0] }}
          transition={{ duration: 1.5, repeat: Infinity }}
          className="flex flex-col items-center gap-2 text-[#A1A1AA]"
        >
          <span className="text-xs uppercase tracking-wider hidden md:block">Découvrir</span>
          <ChevronDown className="w-5 h-5" />
        </motion.div>
      </motion.div>
    </section>
  );
};

// Problem Comparison Section
const ProblemComparison = () => {
  const ref = useRef(null);
  const isInView = useInView(ref, { once: true, margin: "-100px" });

  return (
    <section 
      ref={ref}
      className="py-12 md:py-32 bg-[#F8F9FA] relative overflow-hidden"
      data-testid="comparison-section"
    >
      {/* Strong Grid Background */}
      <div className="absolute inset-0 bg-[linear-gradient(rgba(28,63,249,0.04)_1px,transparent_1px),linear-gradient(90deg,rgba(28,63,249,0.04)_1px,transparent_1px)] bg-[size:32px_32px]" />

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative">
        <SectionHeader 
          number="01"
          label="Le Constat"
          title="OÙ EN ÊTES-VOUS"
          highlight="VRAIMENT ?"
          description="80% des clients choisissent dans le Top 3. Les autres sont invisibles."
        />

        <div className="grid md:grid-cols-2 gap-4 md:gap-8">
          {/* Old Way Card - Grayed out, desaturated */}
          <motion.div 
            initial={{ opacity: 0, x: -50 }}
            animate={isInView ? { opacity: 1, x: 0 } : {}}
            transition={{ duration: 0.6, delay: 0.2 }}
            className="relative p-5 md:p-8 rounded-2xl bg-[#F0F0F0] border-2 border-dashed border-[#D4D4D4] grayscale-[30%]"
            data-testid="card-old-way"
          >
            {/* Diagonal strikethrough effect */}
            <div className="absolute inset-0 overflow-hidden rounded-2xl pointer-events-none">
              <div className="absolute top-0 left-0 w-full h-full bg-[repeating-linear-gradient(135deg,transparent,transparent_10px,rgba(239,68,68,0.03)_10px,rgba(239,68,68,0.03)_20px)]" />
            </div>

            <div className="absolute top-3 md:top-4 right-3 md:right-4 px-2 md:px-3 py-1 rounded-full bg-[#EF4444]/10 text-[10px] md:text-xs font-medium text-[#EF4444] border border-[#EF4444]/20">
              ❌ Vous aujourd'hui ?
            </div>

            <h3 className="text-lg md:text-2xl font-bold text-[#71717A] mb-4 md:mb-6 mt-4 line-through decoration-[#EF4444]/30">
              PERDU DANS LA MASSE
            </h3>

            <ul className="space-y-2.5 md:space-y-4">
              {[
                "10ème+ sur Google Maps dans votre catégorie",
                "Fiche avec 3 photos floues de 2019",
                "Vos clients vont chez celui qui a une vidéo",
                "Vous perdez 15-30 clients/mois sans le savoir"
              ].map((item, i) => (
                <li key={i} className="flex items-start gap-2 md:gap-3">
                  <div className="w-5 h-5 md:w-6 md:h-6 rounded-full bg-[#EF4444]/10 flex items-center justify-center flex-shrink-0 mt-0.5">
                    <X className="w-3 h-3 md:w-4 md:h-4 text-[#EF4444]" />
                  </div>
                  <span className="text-xs md:text-base text-[#71717A]">{item}</span>
                </li>
              ))}
            </ul>
          </motion.div>

          {/* New Way Card - Highlighted, glowing */}
          <motion.div 
            initial={{ opacity: 0, x: 50 }}
            animate={isInView ? { opacity: 1, x: 0 } : {}}
            transition={{ duration: 0.6, delay: 0.4 }}
            className="relative p-5 md:p-8 rounded-2xl bg-white border-2 border-[#1c3ff9] shadow-[0_0_40px_rgba(28,63,249,0.15)]"
            data-testid="card-new-way"
          >
            {/* Subtle grid inside */}
            <div className="absolute inset-0 overflow-hidden rounded-2xl pointer-events-none">
              <div className="absolute inset-0 bg-[linear-gradient(rgba(28,63,249,0.02)_1px,transparent_1px),linear-gradient(90deg,rgba(28,63,249,0.02)_1px,transparent_1px)] bg-[size:20px_20px]" />
            </div>

            <div className="absolute top-3 md:top-4 right-3 md:right-4 px-3 md:px-4 py-1.5 rounded-full bg-[#1c3ff9] text-[10px] md:text-xs font-bold text-white shadow-lg animate-pulse">
              ✓ APRÈS KAPTA
            </div>

            <h3 className="text-lg md:text-2xl font-bold text-[#0A0A0A] mb-4 md:mb-6 mt-4">
              AVEC KAPTA
            </h3>

            <ul className="space-y-2.5 md:space-y-4">
              {[
                "Fiche Google optimisée par des pros",
                "Vidéo pro qui montre votre ambiance réelle",
                "Fiche complète qui rassure avant l'appel",
                "Borne NFC pour collecter des avis facilement"
              ].map((item, i) => (
                <li key={i} className="flex items-start gap-2 md:gap-3">
                  <div className="w-5 h-5 md:w-6 md:h-6 rounded-full bg-[#10B981]/10 flex items-center justify-center flex-shrink-0 mt-0.5">
                    <Check className="w-3 h-3 md:w-4 md:h-4 text-[#10B981]" />
                  </div>
                  <span className="text-xs md:text-base text-[#0A0A0A] font-medium">{item}</span>
                </li>
              ))}
            </ul>
          </motion.div>
        </div>

        {/* What we do */}
        <motion.div 
          initial={{ opacity: 0, y: 30 }}
          animate={isInView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.6, delay: 0.6 }}
          className="mt-8 md:mt-12 grid grid-cols-3 gap-2 md:gap-4"
        >
          {[
            { value: "Vidéo", label: "Professionnelle 4K" },
            { value: "Photos", label: "HD optimisées" },
            { value: "Borne", label: "Collecte d'avis" }
          ].map((stat, i) => (
            <div key={i} className="text-center p-3 md:p-6 rounded-xl bg-white shadow-premium">
              <p className="text-lg md:text-3xl lg:text-4xl font-bold text-[#1c3ff9]">{stat.value}</p>
              <p className="text-[10px] md:text-sm text-[#52525B] mt-0.5 md:mt-1">{stat.label}</p>
            </div>
          ))}
        </motion.div>
      </div>
    </section>
  );
};

// Case Studies Section - Honest version
const CaseStudies = () => {
  const ref = useRef(null);
  const isInView = useInView(ref, { once: true, margin: "-100px" });

  return (
    <section 
      ref={ref}
      className="py-12 md:py-32 bg-white relative"
      data-testid="case-studies-section"
    >
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8">
        <SectionHeader 
          number="02"
          label="Transparence"
          title="PREMIERS PARTENAIRES"
          highlight="EN COURS"
          description=""
        />

        <motion.div
